import { get, post } from "../ultils/request";

export const login = async (username, password) => {
  try {
    // Tạo payload gửi tới API
    const payload = {
      username,
      password,
    };

    // Gửi yêu cầu POST đến API
    const response = await fetch("http://localhost:8080/api/auth/login", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(payload), // Chuyển payload thành chuỗi JSON
    });

    // Kiểm tra trạng thái HTTP
    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
    }

    // Phân tích phản hồi JSON từ backend
    const result = await response.json();
    console.log("Login response:", result);

    return result; // Trả về kết quả từ API
  } catch (error) {
    console.error("Error in login:", error.message);
    throw error; // Ném lỗi ra ngoài để xử lý
  }
};

// export const register = async (options) => {
//   const result = await post("api/auth/register", options);
//   return result;
// };

export const checkExit = async (key, value) => {
  const result = await post(`api/auth/register?${key}=${value}`);
  return result;
};
